function registerShutdownHandlers(schedulers: SchedulerHandle[]): void {
  let isShuttingDown = false;

  const shutdown = async (signal: NodeJS.Signals) => {
    if (isShuttingDown) {
      return;
    }

    isShuttingDown = true;
    writeWorkerLog("log", "shutdown.started", { signal });

    try {
      await Promise.all(schedulers.map((scheduler) => scheduler.stop()));
      await closeDatabasePool();
      writeWorkerLog("log", "shutdown.completed", { signal });
    } catch (error) {
      writeWorkerLog("error", "shutdown.failed", {
        error: error instanceof Error ? error.message : String(error),
        signal,
      });
      process.exitCode = 1;
    } finally {
      process.exit();
    }
  };

  process.once("SIGINT", () => {
    void shutdown("SIGINT");
  });

  process.once("SIGTERM", () => {
    void shutdown("SIGTERM");
  });
}

export async function startWorker(): Promise<SchedulerHandle[]> {
