}

function writeLog(
  level: LogLevel,
  bindings: LogContext,
  message: string,
  context: LogContext = {},
): void {
  if (!shouldLog(level)) {
    return;
  }

  const entry = {
    timestamp: new Date().toISOString(),
    level,
    message,
    ...serializeContext(bindings),
    ...serializeContext(context),
  };

  console[getConsoleMethod(level)](JSON.stringify(entry));
